'use client';

import AdminLayout from '@/components/AdminLayout';
import { useState } from 'react';

export default function AudioPage() {
    const [ttsStatus, setTtsStatus] = useState<'unknown' | 'online' | 'offline'>('unknown');

    const checkTtsServer = async () => {
        try {
            const res = await fetch('http://localhost:8123/health');
            setTtsStatus(res.ok ? 'online' : 'offline');
        } catch {
            setTtsStatus('offline');
        }
    };

    return (
        <AdminLayout>
            <div className="page-header">
                <div className="page-header-top">
                    <div>
                        <h1 className="page-title">Audio Management</h1>
                        <p className="page-subtitle">Voice cloning, TTS generation, and audio library</p>
                    </div>
                    <button className="btn btn-secondary" onClick={checkTtsServer}>
                        <span>🔍</span> Check TTS Server
                    </button>
                </div>
            </div>

            <div className="page-body">
                {/* TTS Server Status */}
                <div className="stats-grid">
                    <div className="card">
                        <div className="card-header">
                            <div className="card-title">🎙️ Chatterbox TTS</div>
                            <span className={`badge ${ttsStatus === 'online' ? 'badge-success' :
                                    ttsStatus === 'offline' ? 'badge-error' : 'badge-pending'
                                }`}>
                                <span className="badge-dot"></span>
                                {ttsStatus === 'online' ? 'Online' : ttsStatus === 'offline' ? 'Offline' : 'Unknown'}
                            </span>
                        </div>
                        <div style={{ fontSize: 13, color: 'var(--text-secondary)' }}>
                            Local server at <code style={{ color: 'var(--accent-primary)' }}>localhost:8123</code>
                            <br />
                            <span style={{ fontSize: 12, color: 'var(--text-tertiary)' }}>MacBook Pro M4 · MPS Acceleration</span>
                        </div>
                    </div>

                    <div className="card">
                        <div className="card-header">
                            <div className="card-title">🗣️ Active Voice</div>
                        </div>
                        <div className="card-value" style={{ fontSize: 24 }}>Default</div>
                        <div style={{ fontSize: 12, color: 'var(--text-tertiary)', marginTop: 4 }}>Voice-cloned profile</div>
                    </div>

                    <div className="card">
                        <div className="card-header">
                            <div className="card-title">📁 Audio Library</div>
                        </div>
                        <div className="card-value">0</div>
                        <div style={{ fontSize: 12, color: 'var(--text-tertiary)', marginTop: 4 }}>Generated audio files</div>
                    </div>
                </div>

                {/* Voice Management */}
                <div className="content-grid">
                    <div className="card">
                        <div className="card-header">
                            <div className="card-title">🗣️ Voice Profiles</div>
                            <button className="btn btn-primary btn-sm">
                                <span>➕</span> Clone Voice
                            </button>
                        </div>
                        <div className="empty-state" style={{ padding: '40px 20px' }}>
                            <div className="empty-state-icon">🎤</div>
                            <div className="empty-state-title">No voice profiles</div>
                            <div className="empty-state-text">
                                Upload a reference audio sample to create a cloned voice for your devotionals.
                            </div>
                        </div>
                    </div>

                    {/* Voice Clone Upload */}
                    <div className="card">
                        <div className="card-title" style={{ marginBottom: 16 }}>📤 Clone a New Voice</div>
                        <div className="form-group">
                            <label className="form-label">Voice Name</label>
                            <input className="form-input" type="text" placeholder="e.g., Pastor John" />
                        </div>
                        <div className="form-group">
                            <label className="form-label">Reference Audio</label>
                            <div className="image-upload">
                                <div className="image-upload-icon">🎵</div>
                                <div className="image-upload-text">Upload a 15-30 second audio sample (.wav, .mp3)</div>
                            </div>
                        </div>
                        <button className="btn btn-primary" style={{ width: '100%' }} disabled>
                            🎙️ Start Cloning
                        </button>
                        <div style={{ fontSize: 11, color: 'var(--text-muted)', marginTop: 8, textAlign: 'center' }}>
                            Requires Chatterbox TTS server to be online
                        </div>
                    </div>
                </div>

                {/* Generated Audio */}
                <div className="card" style={{ marginTop: 24 }}>
                    <div className="card-header">
                        <div className="card-title">📁 Generated Audio</div>
                    </div>
                    <div className="empty-state" style={{ padding: '40px 20px' }}>
                        <div className="empty-state-icon">🎧</div>
                        <div className="empty-state-title">No audio generated yet</div>
                        <div className="empty-state-text">
                            Audio will appear here as devotionals are processed through the pipeline.
                        </div>
                    </div>
                </div>
            </div>
        </AdminLayout>
    );
}
